// Open Data Eval — Metadata Scorecard v4.0
// Reads from window.SCORECARD_DATA (generated by eval/metadata_eval.py)
// Uses global React + ReactDOM — no bundler required

const { useState, useMemo } = React;
const DATA = window.SCORECARD_DATA || [];

// ─── constants ───────────────────────────────────────────────────
const USECASES = [
  { key: "manip",    label: "Manipulation",       field: "manip"    },
  { key: "actRecog", label: "Action recognition",  field: "actRecog" },
  { key: "handPose", label: "Hand pose",           field: "handPose" },
  { key: "nav",      label: "Navigation",          field: "nav"      },
  { key: "robot",    label: "Robot policy",        field: "robot"    },
  { key: "vla",      label: "VLA pretraining",     field: "vla"      },
];
const UC_SHORT = { manip:"Manip", actRecog:"Action", handPose:"Hand", nav:"Nav", robot:"Robot", vla:"VLA" };
const UC_KEY   = { manip:"manipulation", actRecog:"action_recognition",
                   handPose:"hand_pose_estimation", nav:"navigation",
                   robot:"robot_policy_learning", vla:"vla_pretraining" };

const MODALITY_PROFILES = {
  manipulation:          { critical:["RGB video","Depth"], important:["Hand pose annotations","Tactile","Force/torque","Narrations/captions","Proprioception","Gripper state"], bonus:["Audio","IMU","Optical flow","Object bounding boxes","End-effector pose","Segmentation masks"] },
  action_recognition:    { critical:["RGB video"], important:["Audio","Narrations/captions","Optical flow"], bonus:["Eye gaze","Hand pose annotations","IMU","Object bounding boxes"] },
  hand_pose_estimation:  { critical:["RGB video","Hand pose annotations"], important:["Depth","Stereo"], bonus:["Tactile","IMU","Segmentation masks"] },
  navigation:            { critical:["RGB video","IMU"], important:["Depth","SLAM/odometry","3D point clouds"], bonus:["Audio","Stereo","LiDAR","Segmentation masks"] },
  robot_policy_learning: { critical:["RGB video","Proprioception","Gripper state"], important:["Depth","End-effector pose","Narrations/captions","Force/torque"], bonus:["Tactile","Audio","Joint torques"] },
  vla_pretraining:       { critical:["RGB video","Narrations/captions"], important:["Depth","Hand pose annotations","Proprioception"], bonus:["Audio","IMU","Eye gaze","SLAM/odometry","Optical flow"] },
};

// ─── hooks ───────────────────────────────────────────────────────
function useIsMobile() {
  const [mob, setMob] = useState(window.innerWidth < 600);
  React.useEffect(() => {
    const h = () => setMob(window.innerWidth < 600);
    window.addEventListener("resize", h);
    return () => window.removeEventListener("resize", h);
  }, []);
  return mob;
}

// ─── helpers ─────────────────────────────────────────────────────
function avg(vals) {
  const nonNull = vals.filter(v => v != null);
  if (!nonNull.length) return null;
  return Math.round(nonNull.reduce((a, b) => a + b, 0) / nonNull.length * 1000) / 1000;
}
function scoreColor(v) {
  if (v == null) return "var(--c-null)";
  if (v >= 0.7)  return "var(--c-green)";
  if (v >= 0.4)  return "var(--c-amber)";
  return "var(--c-red)";
}
function scoreBg(v) {
  if (v == null) return "var(--c-track)";
  if (v >= 0.7)  return "var(--c-green-bg)";
  if (v >= 0.4)  return "var(--c-amber-bg)";
  return "var(--c-red-bg)";
}
function completenessColor(v) {
  if (v == null) return "var(--c-null)";
  if (v >= 0.8)  return "var(--c-green)";
  if (v >= 0.55) return "var(--c-amber)";
  return "var(--c-red)";
}
function fmtPct(v) { return v == null ? "—" : `${Math.round(v * 100)}`; }
function fmtNum(v) {
  if (v == null) return "—";
  const n = Number(v);
  if (isNaN(n)) return "—";
  if (n >= 10000) return `${Math.round(n / 1000)}k`;
  if (n >= 1000)  return `${(n / 1000).toFixed(1)}k`;
  return Math.round(n).toString();
}

// ─── completion ring ─────────────────────────────────────────────
function CompletionRing({ value, size = 54 }) {
  const stroke = 4.5, r = (size - stroke) / 2;
  const circ = 2 * Math.PI * r;
  const dash = value != null ? circ * Math.min(value, 1) : 0;
  const col = completenessColor(value);
  return (
    <div style={{ position:"relative", width:size, height:size }}>
      <svg width={size} height={size} style={{ transform:"rotate(-90deg)", display:"block" }}>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="var(--c-track)" strokeWidth={stroke} />
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={col} strokeWidth={stroke}
          strokeDasharray={`${dash} ${circ}`} strokeLinecap="round" />
      </svg>
      <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column",
        alignItems:"center", justifyContent:"center", gap:1 }}>
        <span style={{ fontSize:13, fontWeight:700, color:col, lineHeight:1 }}>
          {value != null ? Math.round(value * 100) : "—"}
        </span>
        <span style={{ fontSize:8, color:"var(--c-text-3)", lineHeight:1 }}>%</span>
      </div>
    </div>
  );
}

// ─── collapsible section ─────────────────────────────────────────
function Section({ title, open, onToggle, children }) {
  return (
    <div style={{ borderTop:"1px solid var(--c-border)" }}>
      <button onClick={onToggle} style={{ width:"100%", display:"flex", alignItems:"center",
        justifyContent:"space-between", padding:"10px 0", background:"none", border:"none",
        cursor:"pointer", textAlign:"left" }}>
        <span style={{ fontSize:11, fontWeight:600, color:"var(--c-text-1)",
          letterSpacing:"0.7px", textTransform:"uppercase" }}>{title}</span>
        <span style={{ fontSize:14, color:"var(--c-text-2)", lineHeight:1, display:"inline-block",
          transform:open ? "rotate(180deg)" : "none", transition:"transform 0.15s" }}>▾</span>
      </button>
      {open && <div style={{ paddingBottom:16 }}>{children}</div>}
    </div>
  );
}

// ─── tech stamp (40px) ───────────────────────────────────────────
function TechStamp({ score, display, label }) {
  const isNull  = score == null;
  const isGreen = !isNull && score >= 0.95;
  const isAmber = !isNull && score >= 0.5 && !isGreen;
  const bg   = isNull ? "var(--c-track)"    : isGreen ? "var(--c-green-bg)" : isAmber ? "var(--c-amber-bg)" : "var(--c-red-bg)";
  const bord = isNull ? "var(--c-border)"   : isGreen ? "var(--c-green)"    : isAmber ? "var(--c-amber)"    : "var(--c-red)";
  const col  = isNull ? "var(--c-text-3)"   : isGreen ? "var(--c-green)"    : isAmber ? "var(--c-amber)"    : "var(--c-red)";
  return (
    <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:6 }}>
      <div style={{ position:"relative", width:40, height:40, borderRadius:"50%",
        background:bg, border:`2px solid ${bord}`,
        display:"flex", alignItems:"center", justifyContent:"center" }}>
        <span style={{ fontSize:9, fontWeight:700, color:col, lineHeight:1, userSelect:"none" }}>
          {isNull ? "—" : display}
        </span>
        {isGreen && (
          <div style={{ position:"absolute", top:-3, right:-3, width:13, height:13,
            borderRadius:"50%", background:"var(--c-green)", display:"flex",
            alignItems:"center", justifyContent:"center", border:"2px solid var(--c-surface)" }}>
            <span style={{ color:"white", fontSize:7, fontWeight:700, lineHeight:1 }}>✓</span>
          </div>
        )}
      </div>
      <span style={{ fontSize:10, color:"var(--c-text-3)" }}>{label}</span>
    </div>
  );
}

// ─── device info (below tech stamps) ─────────────────────────────
function DeviceInfo({ d }) {
  const [expanded, setExpanded] = useState(false);
  const raw = (d.captureDevice || "").trim();

  const lensStr = (() => {
    if (!d.lensType) return null;
    if (d.lensType === "varies") return "Mixed lenses";
    const cap = d.lensType.charAt(0).toUpperCase() + d.lensType.slice(1);
    return d.fovDegrees ? `${cap} ${d.fovDegrees}°` : cap;
  })();

  const suffix = lensStr ? ` · ${lensStr}` : "";
  const wrap = { marginTop:10, fontSize:12, color:"var(--c-text-3)", lineHeight:1.5 };
  const btn  = { fontSize:12, color:"var(--c-blue)", background:"none", border:"none",
    cursor:"pointer", padding:0, fontFamily:"inherit",
    textDecoration:"underline", textDecorationStyle:"dotted" };

  if (!raw) {
    return (
      <div style={{ ...wrap, fontStyle:"italic" }}>
        Device not documented{lensStr ? ` · ${lensStr}` : ""}
      </div>
    );
  }

  if (expanded) {
    return (
      <div style={wrap}>
        {raw}{suffix}{" "}
        <button style={btn} onClick={() => setExpanded(false)}>collapse</button>
      </div>
    );
  }

  // Multi-device: contains " + " separator
  const plusIdx = raw.indexOf(" + ");
  if (plusIdx !== -1) {
    const parts = raw.split(" + ");
    const primary = parts[0].replace(/\s*\(.*$/, "").trim();
    const n = parts.length - 1;
    return (
      <div style={wrap}>
        {primary}{" "}
        <button style={btn} onClick={() => setExpanded(true)}>
          +{n} other{n > 1 ? "s" : ""}
        </button>
        {suffix}
      </div>
    );
  }

  // Long string: truncate with show-more
  if (raw.length > 50) {
    return (
      <div style={wrap}>
        {raw.slice(0, 47).trim()}…{" "}
        <button style={btn} onClick={() => setExpanded(true)}>show more</button>
        {suffix}
      </div>
    );
  }

  return <div style={wrap}>{raw}{suffix}</div>;
}

// ─── downstream fit section ──────────────────────────────────────
function DownstreamFitSection({ d, usecase, onUsecaseChange }) {
  const [tiersOpen, setTiersOpen] = useState(false);
  const profile = MODALITY_PROFILES[UC_KEY[usecase]] || {};
  const present = new Set(d.modalities || []);
  const fitLabel = v => v == null ? "No score" : v >= 0.7 ? "Strong fit" : v >= 0.4 ? "Partial fit" : "Weak fit";
  const TIERS = [
    { key:"critical",  label:"Critical"  },
    { key:"important", label:"Important" },
    { key:"bonus",     label:"Bonus"     },
  ];
  return (
    <div>
      <div style={{ display:"flex", gap:5, flexWrap:"wrap", marginBottom:10 }}>
        {USECASES.map(uc => {
          const v = d[uc.field];
          const isActive = uc.key === usecase;
          return (
            <button key={uc.key} onClick={() => onUsecaseChange(uc.key)}
              title={`${fitLabel(v)} for ${uc.label}`}
              style={{ fontSize:11, padding:"4px 10px", borderRadius:20, cursor:"pointer",
                background:scoreBg(v), color:scoreColor(v),
                border:`2px solid ${isActive ? scoreColor(v) : "transparent"}`,
                fontWeight:isActive ? 600 : 400, lineHeight:1.4 }}>
              {UC_SHORT[uc.key]}&thinsp;{fmtPct(v)}
            </button>
          );
        })}
      </div>
      <button onClick={() => setTiersOpen(o => !o)}
        style={{ fontSize:11, color:"var(--c-text-3)", background:"none", border:"none",
          cursor:"pointer", padding:0, display:"inline-flex", alignItems:"center", gap:4,
          marginBottom: tiersOpen ? 8 : 0 }}>
        Modality breakdown
        <span style={{ fontSize:10 }}>{tiersOpen ? "▴" : "▸"}</span>
      </button>
      {tiersOpen && (
        <div style={{ display:"flex", flexDirection:"column", gap:7 }}>
          {TIERS.map(tier => {
            const mods = profile[tier.key] || [];
            if (!mods.length) return null;
            return (
              <div key={tier.key} style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
                <span style={{ fontSize:10, color:"var(--c-text-3)", width:56, flexShrink:0, paddingTop:3 }}>
                  {tier.label}
                </span>
                <div style={{ display:"flex", gap:4, flexWrap:"wrap" }}>
                  {mods.map(m => {
                    const has = present.has(m);
                    return (
                      <span key={m} style={{ fontSize:10, padding:"2px 7px", borderRadius:4,
                        background: has ? "var(--c-green-bg)" : "var(--c-red-bg)",
                        color:      has ? "var(--c-green)"    : "var(--c-red)",
                        textDecoration: has ? "none" : "line-through" }}>
                        {m}
                      </span>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── scale hero ──────────────────────────────────────────────────
function ScaleHero({ d }) {
  const hrsFmt = d.hrs ? Number(d.hrs).toLocaleString() : null;
  const parts = [
    d.envDivCount > 0 ? `${Math.round(d.envDivCount).toLocaleString()} env` : null,
    d.demoParts != null ? `${Math.round(d.demoParts).toLocaleString()} ppl` : null,
    d.demoGeo != null ? `${d.demoGeo} countr${Number(d.demoGeo) === 1 ? "y" : "ies"}` : null,
  ].filter(Boolean);
  return (
    <div style={{ textAlign:"center", padding:"8px 0 10px" }}>
      <div style={{ fontSize:28, fontWeight:700, lineHeight:1,
        color: hrsFmt ? "var(--c-text-1)" : "var(--c-text-3)" }}>
        {hrsFmt ?? "—"}
      </div>
      <div style={{ fontSize:11, color:"var(--c-text-3)", marginTop:4 }}>hours</div>
      {parts.length > 0 && (
        <div style={{ fontSize:13, color:"var(--c-text-2)", marginTop:8, lineHeight:1.4 }}>
          {parts.join(" · ")}
        </div>
      )}
      {d.dlEffHPG != null && (
        <div style={{ marginTop:10, display:"flex", justifyContent:"center" }}>
          <span style={{ fontSize:12, padding:"3px 12px", borderRadius:20, fontWeight:500,
            background:scoreBg(d.dlEff), color:scoreColor(d.dlEff) }}>
            {d.dlEffHPG.toFixed(3)} h/GB
          </span>
        </div>
      )}
    </div>
  );
}

// ─── calibration checklist ────────────────────────────────────────
// false = gray ✗ (not provided), null = gray ? (unknown), true = green ✓
// red ✗ is reserved for future "claimed but broken" state
function CalChecklist({ d }) {
  const items = [
    { key:"calIntrinsics", label:"Intrinsics" },
    { key:"calDistortion", label:"Distortion" },
    { key:"calExtrinsics", label:"Extrinsics" },
    { key:"calValidated",  label:"Validated"  },
  ];
  function Icon({ v }) {
    const style = { fontSize:14, width:16, display:"inline-block", textAlign:"center", lineHeight:1 };
    if (v === null || v === undefined)
      return <span style={{ ...style, color:"var(--c-text-3)" }}>?</span>;
    return v
      ? <span style={{ ...style, color:"var(--c-green)" }}>✓</span>
      : <span style={{ ...style, color:"var(--c-null)"  }}>✗</span>;
  }
  return (
    <div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"6px 20px", marginBottom:8 }}>
        {items.map(it => (
          <div key={it.key} style={{ display:"flex", alignItems:"center", gap:8 }}>
            <Icon v={d[it.key]} />
            <span style={{ fontSize:12, color:"var(--c-text-2)" }}>{it.label}</span>
          </div>
        ))}
      </div>
      {d.camCalNotes && (
        <div style={{ fontSize:10, color:"var(--c-text-3)", lineHeight:1.5 }}>{d.camCalNotes}</div>
      )}
    </div>
  );
}

// ─── annotation coverage ring ─────────────────────────────────────
function AnnotCov({ d }) {
  const v = d.annCov;
  const size = 44, stroke = 4, r = (size - stroke) / 2;
  const circ = 2 * Math.PI * r;
  const dash = v != null ? circ * Math.min(v, 1) : 0;
  const col  = scoreColor(v);
  const pending = !v && d.annCovSource === "pending_paper_review";
  return (
    <div style={{ display:"flex", alignItems:"center", gap:12 }}>
      <div style={{ position:"relative", width:size, height:size, flexShrink:0 }}>
        <svg width={size} height={size} style={{ transform:"rotate(-90deg)", display:"block" }}>
          <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="var(--c-track)" strokeWidth={stroke} />
          {v != null && (
            <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={col} strokeWidth={stroke}
              strokeDasharray={`${dash} ${circ}`} strokeLinecap="round" />
          )}
        </svg>
        <div style={{ position:"absolute", inset:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
          <span style={{ fontSize:9, fontWeight:700, color: v != null ? col : "var(--c-text-3)" }}>
            {v != null ? `${Math.round(v * 100)}%` : "?"}
          </span>
        </div>
      </div>
      <div style={{ flex:1, fontSize:11, color:"var(--c-text-3)", lineHeight:1.5 }}>
        {d.annCovNotes
          ? d.annCovNotes
          : <span style={{ fontStyle:"italic" }}>{pending ? "Pending research" : "Not reported"}</span>}
      </div>
    </div>
  );
}

// ─── accessibility row ────────────────────────────────────────────
function AccessRow({ label, value, score }) {
  const col = scoreColor(score);
  return (
    <div style={{ display:"flex", alignItems:"center", gap:10, padding:"5px 0",
      borderBottom:"1px solid var(--c-track)" }}>
      <span style={{ width:8, height:8, borderRadius:"50%", flexShrink:0,
        background: value ? col : "var(--c-null)" }} />
      <span style={{ fontSize:12, color:"var(--c-text-2)", width:110, flexShrink:0 }}>{label}</span>
      <span style={{ fontSize:12, flex:1,
        color: value ? "var(--c-text-1)" : "var(--c-text-3)",
        fontStyle: value ? "normal" : "italic" }}>
        {value || "—"}
      </span>
    </div>
  );
}

// ─── hardware row ─────────────────────────────────────────────────
function HardwareRow({ label, value }) {
  return (
    <div style={{ display:"flex", gap:12, fontSize:12 }}>
      <span style={{ width:82, flexShrink:0, color:"var(--c-text-3)", textAlign:"right" }}>{label}</span>
      <span style={{ flex:1, color:"var(--c-text-1)", lineHeight:1.5 }} title={value}>{value}</span>
    </div>
  );
}

// ─── score card (v4: two-column) ─────────────────────────────────
function ScoreCard({ d, usecase, onUsecaseChange }) {
  const [open, setOpen] = useState({
    technical:true, reliability:true, access:true,
    scale:true, downstream:true, hardware:false,
  });
  const [modalOpen, setModalOpen] = useState(false);
  const toggle = key => setOpen(s => ({...s, [key]:!s[key]}));
  const isMobile = useIsMobile();

  const shortEdge = d.resW && d.resH ? Math.min(d.resW, d.resH) : null;
  const dlLabel = d.dl == null ? null
    : d.dl >= 0.8
        ? (d.dlFramework && d.dlFramework !== "unspecified" ? d.dlFramework : "Yes")
        : d.dl >= 0.5 ? "Community"
        : "No";
  const accVal = [d.accLevel, d.accUrlStatus]
    .filter(v => v && v !== "Not specified").join(" · ") || null;

  return (
    <div style={{ background:"var(--c-surface)", border:"1px solid var(--c-border)",
      borderRadius:12, maxWidth:800, width:"100%", overflow:"hidden" }}>

      {/* ── header ─────────────────────────────────────────────── */}
      <div style={{ padding:"20px 22px 6px" }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
          <div style={{ flex:1, paddingRight:16 }}>
            <div style={{ fontSize:19, fontWeight:700, color:"var(--c-text-1)", lineHeight:1.2 }}>
              {d.name}
            </div>
            <div style={{ fontSize:12, color:"var(--c-text-2)", marginTop:3 }}>
              {d.cat} · {d.yr}
            </div>
            <div style={{ fontSize:12, color:"var(--c-text-3)", marginTop:2 }}>
              {d.hrs ? `${Number(d.hrs).toLocaleString()} h` : "hours unknown"}
              {d.citations != null
                ? ` · ~${d.citations.toLocaleString()} citations`
                : d.noPaper ? " · No paper" : ""}
            </div>
            <div style={{ marginTop:5 }}>
              <button onClick={() => setModalOpen(o => !o)}
                style={{ fontSize:12, color:"var(--c-text-3)", background:"none", border:"none",
                  cursor:"pointer", padding:0, display:"inline-flex", alignItems:"center", gap:4 }}>
                {d.modCount} {d.modCount === 1 ? "modality" : "modalities"}
                <span style={{ fontSize:10 }}>{modalOpen ? "▴" : "▸"}</span>
              </button>
              {modalOpen && (
                <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginTop:6 }}>
                  {(d.modalities || []).map(m => (
                    <span key={m} style={{ fontSize:10, padding:"2px 7px", borderRadius:4,
                      background:"var(--c-track)", color:"var(--c-text-2)" }}>
                      {m}
                    </span>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:3, flexShrink:0 }}>
            <CompletionRing value={d.completeness} />
            <span style={{ fontSize:9, color:"var(--c-text-3)" }}>fields documented</span>
          </div>
        </div>
      </div>

      {/* ── two-column body ─────────────────────────────────────── */}
      <div style={{
        display:"grid",
        gridTemplateColumns: isMobile ? "1fr" : "1fr 1fr",
        padding:"0 22px",
      }}>

        {/* ── LEFT: Technical · Reliability · Accessibility ─────── */}
        <div style={{ paddingRight: isMobile ? 0 : 18 }}>

          <Section title="Technical" open={open.technical} onToggle={() => toggle("technical")}>
            <div style={{ display:"flex", gap:16, paddingTop:4 }}>
              <TechStamp score={d.fps}
                display={d.fpsRaw != null ? `${d.fpsRaw}fps` : null}
                label="Frame rate" />
              <TechStamp score={d.res}
                display={shortEdge != null ? `${shortEdge}p` : null}
                label="Resolution" />
            </div>
            <DeviceInfo d={d} />
          </Section>

          <Section title="Reliability" open={open.reliability} onToggle={() => toggle("reliability")}>
            <div style={{ fontSize:11, fontWeight:500, color:"var(--c-text-2)", marginBottom:8 }}>
              Annotation coverage
            </div>
            <AnnotCov d={d} />
            <div style={{ fontSize:11, fontWeight:500, color:"var(--c-text-2)",
              marginTop:14, marginBottom:8 }}>
              Camera calibration
            </div>
            <CalChecklist d={d} />
          </Section>

          <Section title="Accessibility & Docs" open={open.access} onToggle={() => toggle("access")}>
            <AccessRow label="License"       value={d.licType}  score={d.lic} />
            <AccessRow label="Accessibility" value={accVal}     score={d.acc} />
            <AccessRow label="Dataloader"    value={dlLabel}    score={d.dl}  />
            <AccessRow label="Documentation"
              value={d.docRating != null ? `${d.docRating}/3` : null} score={d.doc} />
          </Section>

        </div>

        {/* ── RIGHT: Scale · Downstream Fit · Hardware ──────────── */}
        <div style={{
          paddingLeft: isMobile ? 0 : 18,
          borderLeft: isMobile ? "none" : "1px solid var(--c-border)",
        }}>

          <Section title="Scale & Diversity" open={open.scale} onToggle={() => toggle("scale")}>
            <ScaleHero d={d} />
          </Section>

          <Section title="Downstream Fit" open={open.downstream} onToggle={() => toggle("downstream")}>
            <DownstreamFitSection d={d} usecase={usecase} onUsecaseChange={onUsecaseChange} />
          </Section>

          <Section title="Hardware & Format" open={open.hardware} onToggle={() => toggle("hardware")}>
            <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
              {d.captureDevice && <HardwareRow label="Device"      value={d.captureDevice} />}
              {(d.lensType || d.fovDegrees) && (
                <HardwareRow label="Lens"
                  value={[d.lensType, d.fovDegrees ? `${d.fovDegrees}° FOV` : null].filter(Boolean).join(" · ")} />
              )}
              {d.videoFormat  && <HardwareRow label="Video"       value={d.videoFormat} />}
              {d.annotFormat  && <HardwareRow label="Annotations" value={d.annotFormat} />}
            </div>
          </Section>

        </div>
      </div>

      {/* ── footer ─────────────────────────────────────────────── */}
      <div style={{ display:"flex", justifyContent:"space-between", padding:"10px 22px",
        borderTop:"1px solid var(--c-border)", marginTop:6 }}>
        <span style={{ fontSize:10, color:"var(--c-text-3)" }}>Open Data Eval · Metadata Eval v1.0</span>
        <span style={{ fontSize:10, color:"var(--c-text-3)" }}>ISO/IEC 5259-2</span>
      </div>
    </div>
  );
}

// ─── compare table ────────────────────────────────────────────────
function CompareTable({ usecase, sortBy, onSortChange, onRowClick }) {
  const uc = USECASES.find(u => u.key === usecase);

  const sorted = useMemo(() => {
    return DATA.map(d => ({
      ...d,
      techScore: avg([d.fps, d.res]),
      relScore:  avg([d.camCal, d.annCov]),
      accScore:  avg([d.lic, d.acc, d.dl, d.doc]),
    })).sort((a, b) => {
      const av = a[sortBy], bv = b[sortBy];
      if (av == null && bv == null) return 0;
      if (av == null) return 1;
      if (bv == null) return -1;
      return bv - av;
    });
  }, [sortBy, usecase]);

  const active = col => sortBy === col;
  const TH = ({ col, label, right = true }) => (
    <th onClick={() => onSortChange(col)}
      style={{ padding:"7px 6px", textAlign: right ? "right" : "left", fontSize:11, fontWeight:500,
        color: active(col) ? "var(--c-text-1)" : "var(--c-text-2)",
        cursor:"pointer", whiteSpace:"nowrap", borderBottom:"1px solid var(--c-border)",
        userSelect:"none" }}>
      {label}{active(col) ? " ↓" : ""}
    </th>
  );
  const ScoreCell = ({ v }) => (
    <td style={{ textAlign:"right", padding:"6px 6px", fontSize:12,
      color:scoreColor(v), borderBottom:"1px solid var(--c-track)" }}>
      {fmtPct(v)}
    </td>
  );
  const NumCell = ({ v }) => (
    <td style={{ textAlign:"right", padding:"6px 6px", fontSize:12,
      color: v != null ? "var(--c-text-2)" : "var(--c-text-3)",
      borderBottom:"1px solid var(--c-track)" }}>
      {fmtNum(v)}
    </td>
  );
  const subHdr = (label) => (
    <td style={{ padding:"3px 6px", textAlign:"right", fontSize:10,
      color:"var(--c-text-3)", borderBottom:"1px solid var(--c-border)" }}>
      {label}
    </td>
  );

  return (
    <div style={{ overflowX:"auto" }}>
      <table style={{ width:"100%", borderCollapse:"collapse", fontSize:12 }}>
        <thead>
          <tr>
            <TH col="_name"        label="Dataset"     right={false} />
            <TH col="techScore"    label="Technical"   />
            <TH col={uc.field}     label="Fit"         />
            <TH col="relScore"     label="Reliability" />
            <TH col="accScore"     label="Access"      />
            <TH col="hrs"          label="Hours"       />
            <TH col="envDivCount"  label="Envs"        />
            <TH col="demoParts"    label="Ppl"         />
            <TH col="citations"    label="Cit."        />
            <TH col="completeness" label="Cmp"         />
          </tr>
          <tr>
            <td style={{ padding:"3px 6px", fontSize:10, color:"var(--c-text-3)",
              borderBottom:"1px solid var(--c-border)" }} />
            {subHdr("fps+res")}
            {subHdr(uc.label)}
            {subHdr("cal+ann")}
            {subHdr("lic+acc+dl+doc")}
            {subHdr("raw")}
            {subHdr("raw")}
            {subHdr("raw")}
            {subHdr("raw")}
            {subHdr("score")}
          </tr>
        </thead>
        <tbody>
          {sorted.map((row, idx) => (
            <tr key={row.name} onClick={() => onRowClick(row.name)}
              style={{ cursor:"pointer", background: idx % 2 === 1 ? "var(--c-track)" : "transparent" }}
              onMouseOver={e => e.currentTarget.style.background = "var(--c-hover)"}
              onMouseOut={e  => e.currentTarget.style.background = idx % 2 === 1 ? "var(--c-track)" : "transparent"}>
              <td style={{ padding:"6px 6px", fontWeight:500, fontSize:12,
                color:"var(--c-text-1)", borderBottom:"1px solid var(--c-track)", whiteSpace:"nowrap" }}>
                {row.name}
                <span style={{ fontSize:10, color:"var(--c-text-3)", fontWeight:400, marginLeft:5 }}>
                  {row.yr}
                </span>
              </td>
              <ScoreCell v={row.techScore} />
              <ScoreCell v={row[uc.field]} />
              <ScoreCell v={row.relScore}  />
              <ScoreCell v={row.accScore}  />
              <NumCell   v={row.hrs}          />
              <NumCell   v={row.envDivCount}  />
              <NumCell   v={row.demoParts}    />
              <NumCell   v={row.citations}    />
              <ScoreCell v={row.completeness} />
            </tr>
          ))}
        </tbody>
      </table>
      <div style={{ marginTop:10, fontSize:10, color:"var(--c-text-3)" }}>
        Click column header to sort · Click row to open card.&ensp;
        Scores: <span style={{ color:"var(--c-green)" }}>■ ≥70</span>&nbsp;
        <span style={{ color:"var(--c-amber)" }}>■ ≥40</span>&nbsp;
        <span style={{ color:"var(--c-red)" }}>■ &lt;40</span>&nbsp;
        <span style={{ color:"var(--c-null)" }}>■ no data</span>.
        Fit column reflects selected use case.
      </div>
    </div>
  );
}

// ─── app ──────────────────────────────────────────────────────────
function App() {
  const [selected, setSelected] = useState(DATA[0]?.name || "");
  const [usecase,  setUsecase]  = useState("manip");
  const [view,     setView]     = useState("card");
  const [sortBy,   setSortBy]   = useState("completeness");

  const d = DATA.find(x => x.name === selected);
  function handleRowClick(name) { setSelected(name); setView("card"); }

  const TabBtn = ({ id, label }) => (
    <button onClick={() => setView(id)}
      style={{ padding:"5px 14px", fontSize:13,
        fontWeight: view===id ? 600 : 400,
        color:      view===id ? "var(--c-text-1)" : "var(--c-text-2)",
        background: view===id ? "var(--c-surface)" : "transparent",
        border:     view===id ? "1px solid var(--c-border)" : "1px solid transparent",
        borderRadius:6, cursor:"pointer" }}>
      {label}
    </button>
  );

  return (
    <div style={{ maxWidth:860, margin:"0 auto", padding:"24px 20px", fontFamily:"var(--font)" }}>

      {/* page header */}
      <div style={{ marginBottom:22 }}>
        <div style={{ display:"flex", alignItems:"center", gap:10, flexWrap:"wrap" }}>
          <img src="./logo.svg" alt="Open Data Eval logo"
            style={{ height:32, width:"auto", display:"block", flexShrink:0 }} />
          <h1 style={{ fontSize:20, fontWeight:700, margin:0, color:"var(--c-text-1)" }}>
            Open Data Eval
          </h1>
          <span style={{ fontSize:12, color:"var(--c-text-3)", marginLeft:"auto" }}>
            16 datasets · ISO 5259-2 aligned
          </span>
        </div>
        <p style={{ fontSize:13, color:"var(--c-text-2)", marginTop:6, marginBottom:0 }}>
          Quality scores from catalog metadata + paper research.
        </p>
      </div>

      {/* controls */}
      <div style={{ display:"flex", gap:8, marginBottom:18, flexWrap:"wrap", alignItems:"center" }}>
        {view === "card" && (
          <select value={selected} onChange={e => setSelected(e.target.value)}
            style={{ fontSize:13, padding:"5px 10px", borderRadius:6,
              border:"1px solid var(--c-border)", background:"var(--c-surface)",
              color:"var(--c-text-1)", minWidth:200 }}>
            {DATA.map(d => <option key={d.name} value={d.name}>{d.name}</option>)}
          </select>
        )}
        <select value={usecase} onChange={e => setUsecase(e.target.value)}
          style={{ fontSize:13, padding:"5px 10px", borderRadius:6,
            border:"1px solid var(--c-border)", background:"var(--c-surface)",
            color:"var(--c-text-1)" }}>
          {USECASES.map(u => <option key={u.key} value={u.key}>{u.label}</option>)}
        </select>
        <div style={{ marginLeft:"auto", display:"flex", gap:4 }}>
          <TabBtn id="card"    label="Card"    />
          <TabBtn id="compare" label="Compare" />
        </div>
      </div>

      {/* views */}
      {view === "card" && d && (
        <ScoreCard d={d} usecase={usecase} onUsecaseChange={setUsecase} />
      )}
      {view === "compare" && (
        <CompareTable usecase={usecase} sortBy={sortBy}
          onSortChange={setSortBy} onRowClick={handleRowClick} />
      )}

      {/* page footer */}
      <div style={{ marginTop:28, paddingTop:14, borderTop:"1px solid var(--c-border)",
        display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:6 }}>
        <span style={{ fontSize:11, color:"var(--c-text-3)" }}>
          <a href="https://github.com/Varun-Nair/open-data-eval"
            style={{ color:"var(--c-text-3)", textDecoration:"none" }}>open-data-eval</a>
          &nbsp;· CC-BY-4.0 · Varun Nair 2026
        </span>
        <span style={{ fontSize:11, color:"var(--c-text-3)" }}>
          Open Data Eval · Metadata Eval v1.0 · ISO/IEC 5259-2
        </span>
      </div>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById("root")).render(React.createElement(App));
